#include<stdio.h>
int pre[1001],ino[1001],pos[1001],k=0;
void build(int pl,int pr,int il,int ir){if(pl>pr)return;int root=pre[pl];int m=il;while(ino[m]!=root)m++;build(pl+1,pl+m-il,il,m-1);build(pl+m-il+1,pr,m+1,ir);pos[k++]=root;}
int main(){int n;scanf("%d",&n);for(int i=0;i<n;i++)scanf("%d",&pre[i]);for(int i=0;i<n;i++)scanf("%d",&ino[i]);build(0,n-1,0,n-1);for(int i=0;i<n;i++)printf("%d%c",pos[i],i<n-1?' ':'\n');}
